        'product-showcase': { label: 'Products', icon: 'dashicons-products', defaults: { productIds: '', buttonText: 'SHOP NOW', buttonBg: '#000000', buttonTextColor: '#ffffff', cardBg: '#f5f5f5', showDescription: true, padding: '10px 0' } }
